import sys, zlib, re

def extract(path):
    data = open(path,'rb').read()
    out = []
    # find all stream...endstream blocks
    for m in re.finditer(rb'stream\r?\n(.*?)\r?\nendstream', data, re.DOTALL):
        raw = m.group(1)
        try:
            dec = zlib.decompress(raw)
        except Exception:
            try:
                dec = zlib.decompress(raw[1:])
            except Exception:
                continue
        # extract text in parentheses and TJ arrays
        text = []
        # Tj / TJ operators: strings in ( ) 
        for tm in re.finditer(rb'\((?:[^()\\]|\\.)*\)', dec):
            s = tm.group(0)[1:-1]
            s = s.replace(b'\\(',b'(').replace(b'\\)',b')').replace(b'\\\\',b'\\')
            try:
                text.append(s.decode('latin-1'))
            except Exception:
                pass
        if text:
            out.append(''.join(text))
    return '\n'.join(out)

print(extract(sys.argv[1]))
